/*
# Add Sales Onboarding Training Programme for Leapswitch & CloudPe

1. New Data
- Insert a new published course: "Sales Onboarding Training Programme — Leapswitch & CloudPe"
  - Department: Sales
  - Duration: 8h 00m
  - 16 reading lessons organized into 5 phases
  - 5 assessments linked to this course

2. Lesson Structure
- Phase 1: Product and Business Foundations (Lessons 1-6)
- Phase 2: Customer and Market Intelligence (Lessons 7-8)
- Phase 3: Competitive Positioning (Lesson 9)
- Phase 4: Sales Execution and Communication (Lessons 10-13)
- Phase 5: Field Readiness and Certification (Lessons 14-16)

3. Assessment Structure
- Assessment 1: Phase 1 Assessment — Company & Products (11 questions)
- Assessment 2: Phase 2 Assessment — Customers & Market (10 questions)
- Assessment 3: Phase 3 Assessment — Competitive Positioning (11 questions)
- Assessment 4: Phase 4 Assessment — Sales Skills (10 questions)
- Assessment 5: Scenario-Based Final Assessment (10 questions)

4. Notes
- All lessons are type 'reading' with rich HTML content stored in video_url column
- The course is fully editable from the Admin Panel
- Assessments are editable from Admin Panel → Assessment Management
*/

-- Insert the course
INSERT INTO courses (title, description, department, thumbnail_url, duration, status)
VALUES (
  'Sales Onboarding Training Programme — Leapswitch & CloudPe',
  'A complete onboarding programme for new sales joiners covering company background, products, customers, competition, sales skills, and field readiness. By the end of this course, you will be able to confidently represent Leapswitch and CloudPe in any sales conversation.',
  'Sales',
  'https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=800&h=400&fit=crop',
  '8h 00m',
  'published'
)
ON CONFLICT DO NOTHING;

-- Get the course ID
DO $$
DECLARE
  course_id uuid;
BEGIN
  SELECT id INTO course_id FROM courses WHERE title = 'Sales Onboarding Training Programme — Leapswitch & CloudPe';

  IF course_id IS NULL THEN
    RAISE EXCEPTION 'Course not found after insert';
  END IF;

  -- Insert lessons
  INSERT INTO lessons (course_id, title, type, video_url, duration, order_index, section) VALUES
  -- Phase 1: Product and Business Foundations
  (course_id, 'Module 1 — Company Overview', 'reading', '<p>Goal: Understand what Leapswitch and CloudPe do, who they serve, and how to explain the company confidently.</p><h3>1.1 WHO WE ARE — LEAPSWITCH NETWORKS</h3><p>Leapswitch Networks is an infrastructure and cloud company founded in 2006. Over nearly two decades, it has evolved from a hosting provider into a full-scale infrastructure platform serving startups, enterprises, government organizations, and technology companies across India and international markets.</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> Customers choose Leapswitch because it combines reliable infrastructure, responsive support, and long-term partnership value.</div><h3>1.2 WHO WE ARE — CLOUDPE</h3><p>CloudPe is an OpenStack-powered cloud platform built for Indian businesses. It offers computing, storage, GPU, and other cloud services with predictable pricing, local support, and infrastructure hosted in India. Backed by Leapswitch''s infrastructure expertise.</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> Businesses choose CloudPe because it offers enterprise-grade cloud services with predictable pricing, local infrastructure, and strong support.</div>', '45m', 0, 'Phase 1 — Product and Business Foundations'),
  (course_id, 'Module 2 — Cloud Market and Where We Fit', 'reading', '<p>Goal: Understand how IT infrastructure evolved, why businesses moved to the cloud, and where Leapswitch and CloudPe fit within the cloud ecosystem.</p><h3>2.1 HOW INFRASTRUCTURE EVOLVED</h3><p>Before cloud computing, businesses had to buy and manage their own servers. Virtualization allowed multiple virtual servers on one physical machine. Cloud computing changed everything — organizations rent resources and pay only for what they use.</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> Infrastructure evolved from owning physical servers → virtualized environments → cloud-based services.</div><h3>2.2 CLOUD DEPLOYMENT MODELS</h3><ul><li><strong>Public Cloud:</strong> Shared infrastructure, easy to use and scalable</li><li><strong>Private Cloud:</strong> Dedicated to one organization, greater control</li><li><strong>Hybrid Cloud:</strong> Combines public and private</li></ul><h3>2.3 IaaS, PaaS AND SaaS</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Model</th><th>What It Provides</th><th>Examples</th></tr><tr style="background:#f8fafc;"><td>IaaS</td><td>Cloud resources: VMs, storage, networking</td><td>CloudPe VMs, AWS EC2</td></tr><tr><td>PaaS</td><td>Ready-to-use environment for apps</td><td>CloudJiffy, Heroku</td></tr><tr style="background:#f8fafc;"><td>SaaS</td><td>Ready-to-use software</td><td>Gmail, Salesforce</td></tr></table><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> Leapswitch and CloudPe are strongest in the IaaS and PaaS segments.</div>', '40m', 1, 'Phase 1 — Product and Business Foundations'),
  (course_id, 'Module 3 — Leapswitch Infrastructure Portfolio', 'reading', '<p>Goal: Understand Leapswitch''s core offerings and which solutions should receive the highest sales focus.</p><h3>3.1 BARE METAL SERVERS</h3><p>Dedicated physical servers assigned exclusively to a single customer. All hardware resources are reserved for one organization.</p><p><strong>Best For:</strong> Large databases, ERP systems, high-traffic applications, gaming platforms, AI workloads</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> Bare Metal is ideal for customers who need dedicated infrastructure and maximum control.</div><h3>3.2 GPU CLOUD</h3><p>Scalable, on-demand GPU infrastructure without purchasing physical hardware. Used by AI organizations, startups, software companies, and enterprises.</p><h3>3.3 PRIVATE CLOUD</h3><p>A private cloud dedicated to a single organization. Provides greater control, customization, and security.</p><h3>3.4 CURRENT SALES FOCUS</h3><div style="background:#FEF3C7;border:1px solid #F59E0B;padding:12px 16px;border-radius:6px;margin:12px 0;"><strong>Priority Products:</strong><ol><li>CloudPe Virtual Machines</li><li>GPU Infrastructure</li><li>Bare Metal Servers</li><li>Kubernetes</li><li>CloudJiffy</li></ol></div>', '50m', 2, 'Phase 1 — Product and Business Foundations'),
  (course_id, 'Module 4 — CloudPe Portfolio', 'reading', '<p>Goal: Understand the CloudPe product portfolio and how each solution fits customer needs.</p><h3>4.1 CLOUDPE VPS</h3><p>CloudPe is Leapswitch''s cloud platform that provides scalable, on-demand infrastructure without purchasing physical hardware.</p><p><strong>Who Uses CloudPe:</strong> Startups, software companies, enterprises, AI organizations, digital businesses</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> CloudPe enables businesses to scale infrastructure quickly while maintaining flexibility and cost efficiency.</div><h3>4.2 CLOUDJIFFY — PaaS</h3><p>CloudJiffy is Leapswitch''s Platform-as-a-Service (PaaS) offering that allows developers to deploy applications without managing servers.</p><p><strong>Best For:</strong> Web applications, SaaS platforms, development projects, rapid deployment</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> CloudJiffy helps developers deploy applications faster by reducing infrastructure complexity.</div><h3>4.3 MANAGED SERVICES ADD-ONS</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Service</th><th>Purpose</th></tr><tr style="background:#f8fafc;"><td>Colocation</td><td>Host customer-owned hardware</td></tr><tr><td>Backup Services</td><td>Protect critical data</td></tr><tr style="background:#f8fafc;"><td>Managed Services</td><td>Operational support</td></tr><tr><td>Domains & SSL</td><td>Online identity and security</td></tr></table>', '35m', 3, 'Phase 1 — Product and Business Foundations'),
  (course_id, 'Module 5 — Features, Benefits, and Business Value', 'reading', '<p>Goal: Learn how to translate technical features into customer benefits and measurable business outcomes.</p><h3>5.1 WHY FEATURE SELLING DOES NOT WORK</h3><p>Many new salespeople focus on explaining technical features. Customers are usually more interested in the outcomes.</p><div style="background:#FEE2E2;border:1px solid #EF4444;padding:12px 16px;border-radius:6px;margin:8px 0;">❌ <strong>Feature-Focused:</strong> "We provide Kubernetes clusters and NVMe storage."</div><div style="background:#D1FAE5;border:1px solid #10B981;padding:12px 16px;border-radius:6px;margin:8px 0;">✅ <strong>Value-Focused:</strong> "We help your applications run faster, scale more easily, and deliver a better customer experience."</div><h3>5.2 THE THREE LEVELS</h3><ul><li><strong>Feature:</strong> What the product does (e.g., SSD Storage)</li><li><strong>Benefit:</strong> The advantage it creates (e.g., Faster application performance)</li><li><strong>Business Value:</strong> The measurable outcome (e.g., Better user experience, more customers)</li></ul><h3>5.3 SOLUTION MAPPING</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Customer Challenge</th><th>Recommended Solution</th></tr><tr style="background:#f8fafc;"><td>Training AI models is slow</td><td>GPU Cloud</td></tr><tr><td>Traffic spikes during campaigns</td><td>Scalable Cloud Infrastructure</td></tr><tr style="background:#f8fafc;"><td>Need reliable data backup</td><td>Backup & Disaster Recovery</td></tr><tr><td>Want to deploy apps without managing servers</td><td>CloudJiffy</td></tr><tr style="background:#f8fafc;"><td>Need dedicated, high-performance servers</td><td>Bare Metal Servers</td></tr></table>', '45m', 4, 'Phase 1 — Product and Business Foundations'),
  (course_id, 'Module 6 — Internal Team Structure', 'reading', '<p>Goal: Know the internal teams, their responsibilities, and when to involve them during the sales cycle.</p><h3>6.1 DEPARTMENT RESPONSIBILITIES</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Team</th><th>Primary Responsibility</th></tr><tr style="background:#f8fafc;"><td>Demand Generation (DG)</td><td>Prospect identification, lead generation, LinkedIn outreach, cold calling</td></tr><tr><td>Inside Sales Representative (ISR)</td><td>Handles website inquiries, inbound leads, existing customer requests</td></tr><tr style="background:#f8fafc;"><td>Business Development Manager (BDM)</td><td>Discovery meetings, manages opportunities, drives deal closure</td></tr><tr><td>Presales Team</td><td>Technical solution design, architecture recommendations, quotations</td></tr><tr style="background:#f8fafc;"><td>Support Team (L1, L2, L3)</td><td>Resolves technical issues based on escalation levels</td></tr><tr><td>Customer Success Team</td><td>Onboarding, retention, CRM management, relationship management</td></tr></table><h3>6.2 WHAT CUSTOMERS ACTUALLY CARE ABOUT</h3><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Remember:</strong> Customers buy business outcomes, not technical specifications.</div><ul><li>Reliability — Applications remain available</li><li>Performance — Workloads run smoothly</li><li>Cost Control — Predictable infrastructure costs</li><li>Security & Compliance — Meet industry regulations</li><li>Scalability — Infrastructure grows with the business</li><li>Support — Help when issues arise</li></ul>', '35m', 5, 'Phase 1 — Product and Business Foundations'),

  -- Phase 2: Customer and Market Intelligence
  (course_id, 'Module 7 — Ideal Customer Profiles and Pain Points', 'reading', '<p>Goal: Understand who Leapswitch and CloudPe serve, identify ideal customer profiles, and recognize potential customer opportunities.</p><h3>7.1 CUSTOMER SEGMENTS</h3><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:12px 0;"><div style="background:#EFF6FF;padding:12px;border-radius:8px;border-left:4px solid #3B82F6;">🚀 <strong>Startups</strong><br/>Growing businesses needing affordable infrastructure and ability to scale quickly.</div><div style="background:#ECFDF5;padding:12px;border-radius:8px;border-left:4px solid #10B981;">🏢 <strong>SMBs</strong><br/>Organizations looking for reliable infrastructure, predictable pricing, and managed services.</div><div style="background:#FEF3C7;padding:12px;border-radius:8px;border-left:4px solid #F59E0B;">🏭 <strong>Enterprises</strong><br/>Large organizations requiring security, compliance, governance, and high availability.</div><div style="background:#F3E8FF;padding:12px;border-radius:8px;border-left:4px solid #A855F7;">🤖 <strong>AI & ML Companies</strong><br/>Businesses depending on GPU infrastructure and high-performance computing.</div></div><h3>7.2 PAIN POINTS BY SEGMENT</h3><ul><li>💰 <strong>Cost & Billing:</strong> Unexpected charges, complex pricing, poor visibility</li><li>🛠️ <strong>Support & Operational:</strong> Slow support responses, long resolution times</li><li>📈 <strong>Performance & Scalability:</strong> Applications slowing down, difficulty handling growth</li><li>🔒 <strong>Security & Compliance:</strong> Protecting data and meeting regulations</li><li>🤖 <strong>AI & Modern Infrastructure:</strong> Struggling to access resources for AI projects</li></ul><h3>7.3 BUYING TRIGGERS</h3><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> The combination of requirement clarity, urgency, budget, and stakeholder involvement usually indicates a genuine opportunity.</div>', '45m', 6, 'Phase 2 — Customer and Market Intelligence'),
  (course_id, 'Module 8 — Stakeholder Mapping and Customer Matching', 'reading', '<p>Goal: Understand how different stakeholders evaluate solutions and how buying behavior impacts the sales process.</p><h3>8.1 STAKEHOLDER PRIORITIES</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Stakeholder</th><th>Focus</th><th>What They Care About</th></tr><tr style="background:#f8fafc;"><td>CEO / Founder</td><td>Business growth</td><td>Business outcomes, growth, risk, partnerships</td></tr><tr><td>CTO</td><td>Technology strategy</td><td>Scalability, performance, technical fit</td></tr><tr style="background:#f8fafc;"><td>CIO</td><td>Governance, security</td><td>Security, compliance, risk management</td></tr><tr><td>Finance Teams</td><td>Costs and ROI</td><td>Cost control, predictable pricing, budget planning</td></tr><tr style="background:#f8fafc;"><td>Procurement</td><td>Contracts</td><td>Pricing terms, contract flexibility, vendor credibility</td></tr></table><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> Different stakeholders buy for different reasons. Sales teams must understand what matters most to each decision maker.</div><h3>8.2 IDENTIFYING QUALIFIED OPPORTUNITIES</h3><ul><li>✅ Infrastructure Growth</li><li>✅ Cloud Adoption</li><li>✅ Technology Expansion</li><li>✅ AI Initiatives</li><li>✅ Business Expansion</li><li>✅ Modernization Projects</li></ul>', '40m', 7, 'Phase 2 — Customer and Market Intelligence'),

  -- Phase 3: Competitive Positioning
  (course_id, 'Module 9 — Competitive Landscape and Battle Cards', 'reading', '<p>Goal: Understand the competitive landscape and how to confidently respond when customers compare Leapswitch and CloudPe with competing providers.</p><h3>9.1 UNDERSTANDING THE COMPETITIVE LANDSCAPE</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Provider Type</th><th>Examples</th><th>Why Customers Choose Them</th></tr><tr style="background:#f8fafc;"><td>Hyperscalers</td><td>AWS, Azure, Google Cloud</td><td>Large service portfolio, global presence</td></tr><tr><td>Regional Providers</td><td>DigitalOcean, Vultr, Utho</td><td>Simplicity, predictable pricing</td></tr><tr style="background:#f8fafc;"><td>Infrastructure Partners</td><td>MSPs, Hosting Providers</td><td>Managed services, specialized expertise</td></tr><tr><td>Leapswitch & CloudPe</td><td>CloudPe, Leapswitch</td><td>Flexible solutions, personalized support, competitive pricing</td></tr></table><h3>9.2 CLOUDPE VS HYPERSCALERS</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Evaluation Factor</th><th>Hyperscalers</th><th>CloudPe</th></tr><tr style="background:#f8fafc;"><td>Pricing Model</td><td>Complex, variable pricing</td><td>Transparent, predictable pricing</td></tr><tr><td>Support</td><td>Tiered paid support</td><td>Dedicated support included</td></tr><tr style="background:#f8fafc;"><td>Data Location</td><td>Global; data may leave India</td><td>India-hosted; data stays in India</td></tr><tr><td>Complexity</td><td>Hundreds of services</td><td>Focused services; easier to manage</td></tr></table><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> The objective of a battle card is not to prove a competitor is wrong. It is to help customers understand which solution best fits their requirements.</div>', '40m', 8, 'Phase 3 — Competitive Positioning'),

  -- Phase 4: Sales Execution and Communication
  (course_id, 'Module 10 — The Sales Cycle', 'reading', '<p>Goal: Understand how opportunities move through the sales process and how different teams work together to convert prospects into successful customers.</p><h3>10.1 THE NINE-STAGE CUSTOMER JOURNEY</h3><ol><li><strong>Lead Generation</strong> — DG team identifies prospects via LinkedIn, cold calling, referrals</li><li><strong>Lead Qualification</strong> — Assess whether the lead matches ICP and has genuine buying intent</li><li><strong>Discovery Meeting</strong> — Understand customer requirements, challenges, and goals</li><li><strong>Solution Design</strong> — Work with Presales to design the right solution</li><li><strong>Proposal / Quotation</strong> — Present pricing, solution design, and commercial terms</li><li><strong>Commercial Negotiation</strong> — Align on pricing, SLA, and contract terms</li><li><strong>Customer Approval</strong> — Customer confirms the solution and agrees to proceed</li><li><strong>Activation & Onboarding</strong> — KYC, provisioning, and account setup (24-48 hours)</li><li><strong>Ongoing Support & Success</strong> — L1/L2/L3 support, customer success, retention, renewal</li></ol><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> A successful customer journey requires collaboration between multiple teams, from lead generation to post-sales support.</div><h3>10.2 SUPPORT STRUCTURE POST-SALE</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Level</th><th>Responsibility</th></tr><tr style="background:#f8fafc;"><td>L1</td><td>Basic issues and first-level support</td></tr><tr><td>L2</td><td>Intermediate technical issues</td></tr><tr style="background:#f8fafc;"><td>L3</td><td>Advanced technical issues and escalations</td></tr></table>', '40m', 9, 'Phase 4 — Sales Execution and Communication'),
  (course_id, 'Module 11 — Discovery, Qualification and Probing', 'reading', '<p>Goal: Understand how to conduct effective discovery conversations and qualify opportunities.</p><h3>11.1 KEY DISCOVERY QUESTIONS</h3><ul><li>"What workloads are you currently running?"</li><li>"What challenges are you facing with your existing environment?"</li><li>"Are you planning any infrastructure changes this year?"</li><li>"What are the most important factors when evaluating providers?"</li><li>"How do you currently manage cloud costs and support requirements?"</li></ul><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Remember:</strong> Good sales conversations begin with understanding, not pitching.</div><h3>11.2 THE BANT FRAMEWORK</h3><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:12px 0;"><div style="background:#FEF3C7;padding:12px;border-radius:8px;">💰 <strong>Budget</strong><br/>Does the customer have an approved budget?</div><div style="background:#EFF6FF;padding:12px;border-radius:8px;">👤 <strong>Authority</strong><br/>Are you speaking with the decision maker?</div><div style="background:#ECFDF5;padding:12px;border-radius:8px;">📋 <strong>Need</strong><br/>Is there a clear business requirement?</div><div style="background:#F3E8FF;padding:12px;border-radius:8px;">⏰ <strong>Timeline</strong><br/>Is there urgency or a defined timeline?</div></div><h3>11.3 DECISION DRIVERS</h3><ul><li>Price & Value</li><li>Support Quality</li><li>Reliability & Uptime</li><li>Flexibility</li><li>Trust</li></ul>', '35m', 10, 'Phase 4 — Sales Execution and Communication'),
  (course_id, 'Module 12 — Objection Handling — LACE Framework', 'reading', '<p>Goal: Build confidence in handling customer objections and learn how to respond professionally while keeping conversations productive.</p><h3>12.1 UNDERSTANDING CUSTOMER OBJECTIONS</h3><p>Objections are a normal part of the sales process. They usually indicate that customers are evaluating the solution carefully. In many cases, objections indicate interest, not rejection.</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Key Takeaway:</strong> An objection is not a "No." It is often a request for more clarity or confidence.</div><h3>THE LACE FRAMEWORK</h3><div style="display:flex;gap:12px;margin:12px 0;flex-wrap:wrap;"><div style="flex:1;min-width:140px;background:#EFF6FF;padding:12px;border-radius:8px;text-align:center;"><div style="font-size:24px;">👂</div><strong>Step 1 — LISTEN</strong><br/><span style="font-size:12px;">Allow the customer to fully explain</span></div><div style="flex:1;min-width:140px;background:#ECFDF5;padding:12px;border-radius:8px;text-align:center;"><div style="font-size:24px;">🤝</div><strong>Step 2 — ACKNOWLEDGE</strong><br/><span style="font-size:12px;">Show you understand their perspective</span></div><div style="flex:1;min-width:140px;background:#FEF3C7;padding:12px;border-radius:8px;text-align:center;"><div style="font-size:24px;">❓</div><strong>Step 3 — CLARIFY</strong><br/><span style="font-size:12px;">Ask questions to understand the root concern</span></div><div style="flex:1;min-width:140px;background:#F3E8FF;padding:12px;border-radius:8px;text-align:center;"><div style="font-size:24px;">💡</div><strong>Step 4 — EXPLAIN</strong><br/><span style="font-size:12px;">Respond with relevant information and value</span></div></div><h3>12.2 OBJECTION CATEGORIES</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;"><tr style="background:#1E3A8A;color:white;"><th>Category</th><th>Example</th><th>Response Approach</th></tr><tr style="background:#f8fafc;"><td>Pricing</td><td>"This seems expensive."</td><td>Focus on total value, ROI, cost predictability</td></tr><tr><td>Trust</td><td>"We''ve never heard of your company."</td><td>Share experience, references, track record</td></tr><tr style="background:#f8fafc;"><td>Migration</td><td>"Migration sounds risky."</td><td>Explain migration support, proven process</td></tr><tr><td>Support</td><td>"What happens if something goes wrong?"</td><td>Detail SLA commitments, support levels</td></tr></table><h3>12.3 BEST PRACTICES</h3><div style="background:#D1FAE5;border:1px solid #10B981;padding:12px 16px;border-radius:6px;margin:8px 0;">✅ <strong>DO:</strong> Listen fully before responding | Acknowledge first | Ask clarifying questions | Focus on business value | Stay calm and professional</div><div style="background:#FEE2E2;border:1px solid #EF4444;padding:12px 16px;border-radius:6px;margin:8px 0;">❌ <strong>DON''T:</strong> Interrupt the customer | Dismiss concerns | Argue or debate | Immediately offer discounts | Make promises you can''t keep</div>', '40m', 11, 'Phase 4 — Sales Execution and Communication'),
  (course_id, 'Module 13 — Communication and Professionalism', 'reading', '<p>Goal: Understand how to communicate Leapswitch and CloudPe value clearly and confidently during customer conversations.</p><h3>13.1 POSITIONING CLOUDPE</h3><p>CloudPe is not positioned as the largest cloud platform. It focuses on delivering a balance of performance, support, predictable pricing, and local infrastructure.</p><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Remember:</strong> CloudPe combines enterprise-grade cloud infrastructure with predictable pricing and local support.</div><h3>13.2 SIMPLE SALES MESSAGING FORMULA</h3><p><strong>Customer Challenge → Solution → Business Benefit</strong></p><div style="background:#FEE2E2;border:1px solid #EF4444;padding:12px 16px;border-radius:6px;margin:8px 0;">❌ Instead of: "We provide virtualized cloud infrastructure with scalable compute resources."</div><div style="background:#D1FAE5;border:1px solid #10B981;padding:12px 16px;border-radius:6px;margin:8px 0;">✅ Say: "You can deploy infrastructure quickly and scale resources as your business grows."</div><h3>13.3 COMMUNICATION BEST PRACTICES</h3><ul><li>Listen More Than You Speak</li><li>Avoid Unnecessary Technical Jargon</li><li>Be Clear and Concise</li><li>Ask Questions</li><li>Focus on the Customer</li></ul><div style="border-left:4px solid #2563EB;padding:12px 16px;background:#EFF6FF;margin:12px 0;border-radius:6px;"><strong>Remember:</strong> Successful sales conversations are customer-focused, not product-focused.</div>', '30m', 12, 'Phase 4 — Sales Execution and Communication'),

  -- Phase 5: Field Readiness and Certification
  (course_id, 'Module 14 — Shadow Calls', 'reading', '<p>Goal: Observe experienced sales professionals during real customer interactions to understand how successful sales conversations are conducted in practice.</p><h3>ASSIGNMENT</h3><p>Shadow <strong>20 valid customer calls or meetings</strong> conducted by experienced sales team members during your first two weeks on the floor.</p><h3>VALID CALL CRITERIA</h3><ul><li>Customer interaction must be genuine</li><li>Minimum conversation duration: 60 seconds</li><li>Wrong numbers should NOT be counted</li><li>Ring-no-response (RNR) calls should NOT be counted</li></ul><h3>OBSERVATION CHECKLIST</h3><ul><li>✅ How the conversation is opened</li><li>✅ Discovery questions asked</li><li>✅ Customer pain points discussed</li><li>✅ Solution positioning approach</li><li>✅ Objections raised and handled</li><li>✅ Communication style and professionalism</li></ul><h3>SUBMISSION FORMAT</h3><p>For each call, document: Prospect Name | Salesperson Shadowed | What They Pitched | How They Pitched | Pitch Outcome | Your Learnings</p>', '25m', 13, 'Phase 5 — Field Readiness and Certification'),
  (course_id, 'Module 15 — Mock Sales Flow and Pitch Video', 'reading', '<p>Goal: Practice a complete sales conversation demonstrating your ability to identify customer requirements, recommend suitable solutions, communicate business value, handle objections, and define clear next steps.</p><h3>15.1 FULL MOCK SALES FLOW</h3><p>You must demonstrate:</p><ul><li>✅ Ask discovery questions</li><li>✅ Identify customer pain points</li><li>✅ Recommend suitable solutions</li><li>✅ Explain business value</li><li>✅ Handle objections professionally</li><li>✅ Define clear next steps</li></ul><h3>15.2 MOCK PITCH VIDEO SUBMISSION</h3><p>Record and upload a 2–5 minute video presenting a sales pitch for a Leapswitch or CloudPe product.</p><p><strong>Your pitch must include:</strong></p><ol><li>Introduction — Introduce yourself and the company</li><li>Customer Requirement — Describe the customer''s challenge</li><li>Recommended Solution — Recommend the most suitable solution</li><li>Business Value — Explain benefits and outcomes</li><li>Next Steps — Conclude professionally with a clear next step</li></ol>', '30m', 14, 'Phase 5 — Field Readiness and Certification'),
  (course_id, 'Module 16 — Quick Reference Toolkit & Technical Glossary', 'reading', '<p>Goal: Access official resources, product brochures, and a technical glossary for quick reference during sales conversations.</p><h3>OFFICIAL WEBSITES</h3><ul><li>CloudPe: https://www.cloudpe.com/</li><li>Leapswitch Networks: https://leapswitch.com/</li><li>CloudPe Knowledge Base: https://www.cloudpe.com/knowledge-base/</li><li>Leapswitch Knowledge Base: https://service.leapswitch.com/knowledgebase/</li></ul><h3>PRODUCT BROCHURES</h3><ul><li>CloudPe Brochure: https://drive.google.com/file/d/1Wnp_8t6lT0XPS9uxLcJo-y5QkzPiHAh_/view</li><li>Leapswitch Services Brochure: https://drive.google.com/file/d/19L2BRDs9pkHYmJYY4ip8o_RDC-xVdPHH/view</li></ul><h3>SLA AND POLICY DOCUMENTS</h3><ul><li>CloudPe SLA: https://www.cloudpe.com/service-level-agreement/</li><li>Leapswitch SLA: https://leapswitch.com/service-level-agreement.php</li><li>CloudPe Terms: https://www.cloudpe.com/terms-of-service/</li><li>Leapswitch Terms: https://leapswitch.com/terms-of-service.php</li></ul><h3>TECHNICAL GLOSSARY — 25 ESSENTIAL TERMS</h3><table style="width:100%;border-collapse:collapse;margin:12px 0;font-size:13px;"><tr style="background:#1E3A8A;color:white;"><th>Term</th><th>Definition</th></tr><tr style="background:#f8fafc;"><td>Bare Metal</td><td>A physical server dedicated entirely to one customer</td></tr><tr><td>VPS</td><td>A portion of a physical server allocated using virtualisation</td></tr><tr style="background:#f8fafc;"><td>GPU</td><td>High-performance chip used for AI, ML, and rendering</td></tr><tr><td>IaaS</td><td>Infrastructure as a Service — raw computing resources</td></tr><tr style="background:#f8fafc;"><td>PaaS</td><td>Platform as a Service — managed platform for apps</td></tr><tr><td>SaaS</td><td>Software as a Service — complete application delivered online</td></tr><tr style="background:#f8fafc;"><td>SLA</td><td>Service Level Agreement — contract defining minimum standards</td></tr><tr><td>Latency</td><td>Time it takes data to travel from one point to another</td></tr><tr style="background:#f8fafc;"><td>Bandwidth</td><td>Amount of data that can be transferred per second</td></tr><tr><td>Colocation</td><td>Hosting a customer''s own servers in our data centre</td></tr><tr style="background:#f8fafc;"><td>Private Cloud</td><td>Cloud infrastructure dedicated exclusively to one organisation</td></tr><tr><td>Hybrid Cloud</td><td>Combination of private and public cloud environments</td></tr><tr style="background:#f8fafc;"><td>Managed Services</td><td>Provider handles ongoing management and maintenance</td></tr><tr><td>KYC</td><td>Know Your Customer — identity verification before activation</td></tr><tr style="background:#f8fafc;"><td>Provisioning</td><td>Setting up and configuring a server or service</td></tr><tr><td>Redundancy</td><td>Backup systems so failure does not cause downtime</td></tr><tr style="background:#f8fafc;"><td>Failover</td><td>Automatic switching to backup when primary fails</td></tr><tr><td>Disaster Recovery</td><td>Systems that allow recovery from major failures</td></tr><tr style="background:#f8fafc;"><td>CDN</td><td>Content Delivery Network — servers distributed globally</td></tr></table>', '25m', 15, 'Phase 5 — Field Readiness and Certification')
  ON CONFLICT DO NOTHING;

